import { Entity, PrimaryGeneratedColumn, Column, ManyToOne } from 'typeorm';
import { Order } from './order.entity';

@Entity('order_items')
export class OrderItem {
  @PrimaryGeneratedColumn()
  id: number;

  @Column()
  productId: number; // Référence à l'ID du produit original

  @Column()
  productName: string; // SNAPSHOT

  @Column({ type: 'decimal', precision: 10, scale: 2 })
  unitPrice: number; // SNAPSHOT - prix au moment de l'achat

  @Column()
  quantity: number;

  @Column({ type: 'decimal', precision: 10, scale: 2 })
  total: number; // unitPrice * quantity

  @ManyToOne(() => Order, (order) => order.items)
  order: Order;
}
```
L'importance du snapshot : les prix et noms des produits peuvent changer après l'achat. En stockant ces informations dans OrderItem, on garantit que la facture du client reflète exactement ce qu'il a payé, même si le vendeur modifie le prix plus tard. C'est une exigence légale et comptable.

