export class OrderStatusLog {
  @PrimaryGeneratedColumn()
  id: number;

  @ManyToOne(() => Order)
  order: Order;

  @Column({ type: 'enum', enum: OrderStatus })
  fromStatus: OrderStatus;

  @Column({ type: 'enum', enum: OrderStatus })
  toStatus: OrderStatus;

  @Column()
  changedBy: string; // 'customer', 'admin:123', 'system'

  @Column({ type: 'text', nullable: true })
